<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  :root { --bg:#f4f5f7; --card:#fff; --line:#e0e3e8; --accent:#3b6ef5; --danger:#e5484d; --text:#1c2024; --muted:#6b7280; }
  * { box-sizing: border-box; }
  body { margin:0; font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif; background:var(--bg); color:var(--text); line-height:1.4; }
  .wrap { max-width: 860px; margin: 0 auto; padding: 24px 16px 60px; }
  h1 { font-size: 1.5rem; margin: 0 0 4px; }
  .sub { color: var(--muted); margin: 0 0 20px; font-size: .9rem; }
  .card { background:var(--card); border:1px solid var(--line); border-radius:10px; padding:16px; margin-bottom:20px; }
  .card h2 { font-size: 1rem; margin: 0 0 12px; }
  form .grid { display:grid; grid-template-columns: repeat(auto-fit, minmax(150px,1fr)); gap:12px; }
  label { display:block; font-size:.78rem; color:var(--muted); margin-bottom:4px; font-weight:600; text-transform:uppercase; letter-spacing:.03em; }
  input, select, button { font: inherit; padding:9px 10px; border:1px solid var(--line); border-radius:7px; background:#fff; color:var(--text); width:100%; }
  input:focus, select:focus { outline:2px solid var(--accent); outline-offset:-1px; border-color:var(--accent); }
  button { cursor:pointer; }
  #add-expense { background:var(--accent); color:#fff; border-color:var(--accent); font-weight:600; margin-top:14px; width:auto; padding:10px 22px; }
  #add-expense:hover { filter:brightness(1.05); }
  #form-error { color:var(--danger); font-size:.9rem; margin-top:10px; min-height:1.1em; font-weight:600; }
  #form-error:empty { display:none; }
  .filters .grid { display:grid; grid-template-columns: repeat(auto-fit, minmax(150px,1fr)); gap:12px; align-items:end; }
  .summary { display:flex; flex-wrap:wrap; gap:10px; align-items:center; margin-bottom:16px; }
  .total-box { background:var(--accent); color:#fff; padding:10px 16px; border-radius:8px; font-weight:700; font-size:1.05rem; }
  .cat-total { background:#eef1f6; border:1px solid var(--line); padding:8px 12px; border-radius:8px; font-size:.85rem; }
  .cat-total b { text-transform:capitalize; }
  table { width:100%; border-collapse:collapse; }
  th, td { text-align:left; padding:10px 8px; border-bottom:1px solid var(--line); font-size:.92rem; }
  th { font-size:.75rem; text-transform:uppercase; color:var(--muted); letter-spacing:.03em; }
  td.amt { font-variant-numeric: tabular-nums; font-weight:600; }
  .tag { display:inline-block; padding:2px 9px; border-radius:20px; background:#eef1f6; font-size:.8rem; text-transform:capitalize; }
  .exp-del { background:transparent; border:none; color:var(--danger); cursor:pointer; font-weight:700; width:auto; padding:4px 8px; border-radius:6px; }
  .exp-del:hover { background:#fdecec; }
  .empty { color:var(--muted); text-align:center; padding:20px; font-style:italic; }
</style>
</head>
<body>
<div class="wrap">
  <h1>Personal Expense Tracker</h1>
  <p class="sub">Track spending, filter by category and date, and see totals update live.</p>

  <div class="card">
    <h2>Add expense</h2>
    <form id="expense-form" novalidate>
      <div class="grid">
        <div>
          <label for="amount">Amount</label>
          <input type="number" id="amount" step="0.01" placeholder="0.00" inputmode="decimal">
        </div>
        <div>
          <label for="category">Category</label>
          <select id="category">
            <option value="groceries">groceries</option>
            <option value="transport">transport</option>
            <option value="bills">bills</option>
            <option value="fun">fun</option>
          </select>
        </div>
        <div>
          <label for="date">Date</label>
          <input type="date" id="date">
        </div>
        <div>
          <label for="note">Note (optional)</label>
          <input type="text" id="note" placeholder="e.g. weekly shop">
        </div>
      </div>
      <button type="submit" id="add-expense">Add expense</button>
      <div id="form-error" role="alert"></div>
    </form>
  </div>

  <div class="card filters">
    <h2>Filters</h2>
    <div class="grid">
      <div>
        <label for="filter-category">Category</label>
        <select id="filter-category">
          <option value="all">all</option>
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </div>
      <div>
        <label for="filter-from">From</label>
        <input type="date" id="filter-from">
      </div>
      <div>
        <label for="filter-to">To</label>
        <input type="date" id="filter-to">
      </div>
      <div>
        <button type="button" id="clear-filters" style="width:auto;">Clear filters</button>
      </div>
    </div>
  </div>

  <div class="card">
    <div class="summary">
      <div class="total-box">Total: <span id="total">0.00</span></div>
      <div class="cat-total" data-cat="groceries"><b>groceries</b>: <span>0.00</span></div>
      <div class="cat-total" data-cat="transport"><b>transport</b>: <span>0.00</span></div>
      <div class="cat-total" data-cat="bills"><b>bills</b>: <span>0.00</span></div>
      <div class="cat-total" data-cat="fun"><b>fun</b>: <span>0.00</span></div>
    </div>
    <table>
      <thead>
        <tr><th>Amount</th><th>Category</th><th>Date</th><th>Note</th><th></th></tr>
      </thead>
      <tbody id="expense-list"></tbody>
    </table>
    <div id="empty-msg" class="empty">No expenses to show.</div>
  </div>
</div>

<script>
(function () {
  "use strict";
  var STORAGE_KEY = "expense-tracker-v1";
  var CATEGORIES = ["groceries", "transport", "bills", "fun"];

  var expenses = load();

  var form = document.getElementById("expense-form");
  var amountEl = document.getElementById("amount");
  var categoryEl = document.getElementById("category");
  var dateEl = document.getElementById("date");
  var noteEl = document.getElementById("note");
  var errorEl = document.getElementById("form-error");

  var filterCat = document.getElementById("filter-category");
  var filterFrom = document.getElementById("filter-from");
  var filterTo = document.getElementById("filter-to");
  var clearBtn = document.getElementById("clear-filters");

  var listEl = document.getElementById("expense-list");
  var totalEl = document.getElementById("total");
  var emptyMsg = document.getElementById("empty-msg");

  // Default the entry date to today for convenience.
  dateEl.value = todayISO();

  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var parsed = JSON.parse(raw);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }

  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch (e) { /* storage may be unavailable; ignore */ }
  }

  function todayISO() {
    var d = new Date();
    var m = String(d.getMonth() + 1).padStart(2, "0");
    var day = String(d.getDate()).padStart(2, "0");
    return d.getFullYear() + "-" + m + "-" + day;
  }

  function fmt(n) { return n.toFixed(2); }

  function uid() {
    return "e" + Date.now() + "_" + Math.floor(Math.random() * 1e6);
  }

  form.addEventListener("submit", function (ev) {
    ev.preventDefault();
    var raw = amountEl.value.trim();
    var amount = Number(raw);

    if (raw === "" || isNaN(amount) || amount <= 0) {
      errorEl.textContent = "Please enter a positive amount.";
      return;
    }
    if (!dateEl.value) {
      errorEl.textContent = "Please choose a date.";
      return;
    }

    expenses.push({
      id: uid(),
      amount: amount,
      category: categoryEl.value,
      date: dateEl.value,
      note: noteEl.value.trim()
    });

    save();
    errorEl.textContent = "";
    amountEl.value = "";
    noteEl.value = "";
    amountEl.focus();
    render();
  });

  listEl.addEventListener("click", function (ev) {
    var btn = ev.target.closest(".exp-del");
    if (!btn) return;
    var id = btn.getAttribute("data-id");
    expenses = expenses.filter(function (e) { return e.id !== id; });
    save();
    render();
  });

  filterCat.addEventListener("change", render);
  filterFrom.addEventListener("change", render);
  filterTo.addEventListener("change", render);
  clearBtn.addEventListener("click", function () {
    filterCat.value = "all";
    filterFrom.value = "";
    filterTo.value = "";
    render();
  });

  function isVisible(e) {
    if (filterCat.value !== "all" && e.category !== filterCat.value) return false;
    if (filterFrom.value && e.date < filterFrom.value) return false;
    if (filterTo.value && e.date > filterTo.value) return false;
    return true;
  }

  function render() {
    // Newest first: sort a copy by date desc, then insertion order (id) desc.
    var sorted = expenses.slice().sort(function (a, b) {
      if (a.date !== b.date) return a.date < b.date ? 1 : -1;
      return a.id < b.id ? 1 : -1;
    });

    var visible = sorted.filter(isVisible);

    listEl.innerHTML = "";
    visible.forEach(function (e) {
      var tr = document.createElement("tr");
      tr.className = "expense";

      var tdAmt = document.createElement("td");
      tdAmt.className = "amt";
      tdAmt.textContent = fmt(e.amount);

      var tdCat = document.createElement("td");
      var tag = document.createElement("span");
      tag.className = "tag";
      tag.textContent = e.category;
      tdCat.appendChild(tag);

      var tdDate = document.createElement("td");
      tdDate.textContent = e.date;

      var tdNote = document.createElement("td");
      tdNote.textContent = e.note || "";

      var tdDel = document.createElement("td");
      var del = document.createElement("button");
      del.className = "exp-del";
      del.type = "button";
      del.setAttribute("data-id", e.id);
      del.textContent = "Delete";
      tdDel.appendChild(del);

      tr.appendChild(tdAmt);
      tr.appendChild(tdCat);
      tr.appendChild(tdDate);
      tr.appendChild(tdNote);
      tr.appendChild(tdDel);
      listEl.appendChild(tr);
    });

    emptyMsg.style.display = visible.length ? "none" : "block";

    // Totals over visible rows only.
    var total = 0;
    var catTotals = { groceries: 0, transport: 0, bills: 0, fun: 0 };
    visible.forEach(function (e) {
      total += e.amount;
      if (catTotals.hasOwnProperty(e.category)) catTotals[e.category] += e.amount;
    });

    totalEl.textContent = fmt(total);
    CATEGORIES.forEach(function (cat) {
      var box = document.querySelector('.cat-total[data-cat="' + cat + '"] span');
      if (box) box.textContent = fmt(catTotals[cat]);
    });
  }

  render();
})();
</script>
</body>
</html>
